BEGIN TRANSACTION;
CREATE TABLE contact_messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR,
    email VARCHAR,
    subject VARCHAR,
    message TEXT,
    sent_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE export_reports (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    authority_id INTEGER,
    station VARCHAR,
    forecast_period VARCHAR,
    report_type VARCHAR,
    generated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE flood_data (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    uc_id INTEGER,
    station VARCHAR,
    location VARCHAR,
    rainfall FLOAT DEFAULT 0.0,
    humidity FLOAT DEFAULT 50.0,
    temperature FLOAT DEFAULT 25.0,
    river_level FLOAT DEFAULT 5.0,
    current_discharge FLOAT DEFAULT 5000.0,
    prediction_result FLOAT,
    risk_percentage FLOAT,
    risk_level VARCHAR,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE reports (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR,
    location VARCHAR,
    description TEXT,
    submitted_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE shelters (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR,
    location VARCHAR,
    district VARCHAR,
    capacity INTEGER,
    occupied INTEGER DEFAULT 0,
    status VARCHAR,
    facilities TEXT,
    uc_id INTEGER,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE union_councils (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    uc_name VARCHAR,
    district VARCHAR,
    station VARCHAR,
    distance_to_river_km FLOAT,
    elevation_m FLOAT,
    population INTEGER,
    geometry TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR,
    email VARCHAR UNIQUE,
    password VARCHAR,
    role VARCHAR DEFAULT 'authority',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX ix_users_email ON users(email);
CREATE INDEX ix_union_councils_uc_name ON union_councils(uc_name);
CREATE INDEX ix_union_councils_district ON union_councils(district);
CREATE INDEX ix_union_councils_station ON union_councils(station);
CREATE INDEX ix_flood_data_station ON flood_data(station);
DELETE FROM "sqlite_sequence";
COMMIT;